blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>pozycję przysłówków i okoliczników</strong> w angielskim zdaniu: częstotliwości, sposobu, miejsca, czasu i stopnia.",
    "rules": [
        {
            "label": "Frequency",
            "color": "emerald",
            "text": "<strong>always, often, never</strong> zwykle stoją przed głównym czasownikiem, ale po <em>to be</em>:",
            "example": "She always eats breakfast."
        },
        {
            "label": "Manner",
            "color": "blue",
            "text": "<strong>quickly, well, carefully</strong> często pojawiają się pod koniec zdania:",
            "example": "He speaks English fluently."
        },
        {
            "label": "Place + Time",
            "color": "amber",
            "text": "Przy kilku okolicznikach często działa kolejność: <strong>Manner → Place → Time</strong>:",
            "example": "She worked hard in London last year."
        }
    ]
}

{
    "title": "1. Trzy główne pozycje przysłówków",
    "intro": "Przysłówki mogą pojawić się w trzech podstawowych miejscach w zdaniu:",
    "items": [
        {
            "label": "Front",
            "title": "Na początku",
            "subtitle": "Przed podmiotem: Yesterday, I met my friend."
        },
        {
            "label": "Mid",
            "title": "W środku",
            "subtitle": "Między podmiotem a czasownikiem albo po operatorze: She always drinks coffee."
        },
        {
            "label": "End",
            "title": "Na końcu",
            "subtitle": "Po czasowniku lub dopełnieniu: He speaks English fluently."
        }
    ]
}

{
    "title": "2. Przysłówki częstotliwości",
    "sections": [
        {
            "label": "Przed głównym czasownikiem",
            "color": "emerald",
            "description": "Przysłówki <strong>always, usually, often, sometimes, rarely, never</strong> stoją zwykle przed głównym czasownikiem.",
            "examples": [
                {
                    "en": "She always eats breakfast.",
                    "ua": "Ona zawsze je śniadanie."
                },
                {
                    "en": "I often go to the gym.",
                    "ua": "Często chodzę na siłownię."
                },
                {
                    "en": "They never drink coffee.",
                    "ua": "Oni nigdy nie piją kawy."
                }
            ]
        },
        {
            "label": "Po to be",
            "color": "sky",
            "description": "Jeśli w zdaniu występuje <strong>to be</strong>, przysłówek częstotliwości zwykle stoi po tej formie.",
            "examples": [
                {
                    "en": "He is always late.",
                    "ua": "On zawsze się spóźnia."
                },
                {
                    "en": "She is usually happy.",
                    "ua": "Ona jest zwykle szczęśliwa."
                },
                {
                    "en": "They are rarely bored.",
                    "ua": "Oni rzadko się nudzą."
                }
            ]
        },
        {
            "label": "Po operatorze",
            "color": "amber",
            "description": "W bardziej złożonych czasach przysłówek pojawia się po operatorze, np. po <em>have</em> lub <em>will</em>.",
            "examples": [
                {
                    "en": "I have never been to Paris.",
                    "ua": "Nigdy nie byłem w Paryżu."
                },
                {
                    "en": "She has always wanted a dog.",
                    "ua": "Ona zawsze chciała mieć psa."
                },
                {
                    "en": "They will usually arrive on time.",
                    "ua": "Oni zwykle przyjadą na czas."
                }
            ],
            "note": "Niektóre formy, np. <em>sometimes</em> albo <em>usually</em>, mogą też stać na początku zdania dla podkreślenia."
        }
    ]
}

{
    "title": "3. Przysłówki sposobu",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Przysłówki takie jak <strong>quickly, slowly, carefully, well, badly, beautifully</strong> najczęściej stoją na końcu zdania.",
            "examples": [
                {
                    "en": "She sings beautifully.",
                    "ua": "Ona pięknie śpiewa."
                },
                {
                    "en": "He finished the test quickly.",
                    "ua": "On szybko skończył test."
                },
                {
                    "en": "They work hard every day.",
                    "ua": "Oni ciężko pracują każdego dnia."
                }
            ]
        },
        {
            "label": "Po dopełnieniu",
            "color": "sky",
            "description": "Jeśli w zdaniu jest dopełnienie, przysłówek sposobu zwykle pojawia się po nim.",
            "examples": [
                {
                    "en": "She speaks English fluently.",
                    "ua": "Ona mówi po angielsku płynnie."
                },
                {
                    "en": "He plays the piano well.",
                    "ua": "On dobrze gra na pianinie."
                },
                {
                    "en": "They did the work carefully.",
                    "ua": "Oni wykonali tę pracę starannie."
                }
            ],
            "note": "❌ <em>She speaks fluently English</em> brzmi nienaturalnie."
        }
    ]
}

{
    "title": "4. Okoliczniki miejsca",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Okoliczniki miejsca, np. <strong>here, there, at home, in the park, at school</strong>, stoją zwykle pod koniec zdania.",
            "examples": [
                {
                    "en": "She lives here.",
                    "ua": "Ona mieszka tutaj."
                },
                {
                    "en": "He works at the office.",
                    "ua": "On pracuje w biurze."
                },
                {
                    "en": "The children play in the park.",
                    "ua": "Dzieci bawią się w parku."
                }
            ]
        },
        {
            "label": "Na początku dla akcentu",
            "color": "sky",
            "description": "W stylu bardziej formalnym albo dla efektu niektóre okoliczniki miejsca mogą stać na początku zdania.",
            "examples": [
                {
                    "en": "Here is your book.",
                    "ua": "Oto twoja książka."
                },
                {
                    "en": "There goes the bus.",
                    "ua": "Oto odjeżdża autobus."
                }
            ]
        }
    ]
}

{
    "title": "5. Okoliczniki czasu",
    "sections": [
        {
            "label": "Na końcu zdania",
            "color": "emerald",
            "description": "Okoliczniki czasu, np. <strong>yesterday, today, tomorrow, last week, every day</strong>, bardzo często stoją na końcu zdania.",
            "examples": [
                {
                    "en": "I wake up at 6 o'clock.",
                    "ua": "Budzę się o szóstej."
                },
                {
                    "en": "She studies English every day.",
                    "ua": "Ona codziennie uczy się angielskiego."
                },
                {
                    "en": "We went to the cinema last night.",
                    "ua": "Wczoraj wieczorem poszliśmy do kina."
                }
            ]
        },
        {
            "label": "Na początku dla akcentu",
            "color": "sky",
            "description": "Jeśli chcesz zaakcentować czas, możesz przesunąć okolicznik na początek zdania.",
            "examples": [
                {
                    "en": "Yesterday, I met an old friend.",
                    "ua": "Wczoraj spotkałem starego przyjaciela."
                },
                {
                    "en": "Every morning, she jogs in the park.",
                    "ua": "Każdego ranka biega w parku."
                }
            ]
        },
        {
            "label": "Kilka informacji o czasie",
            "color": "amber",
            "description": "Gdy pojawia się kilka elementów czasu, bardziej szczegółowa informacja zwykle stoi wcześniej.",
            "examples": [
                {
                    "en": "He is leaving at 10 a.m. on Monday.",
                    "ua": "Wyjeżdża w poniedziałek o 10 rano."
                }
            ]
        }
    ]
}

{
    "title": "6. Kolejność okoliczników: Manner → Place → Time",
    "intro": "Gdy pod koniec zdania masz kilka okoliczników, zwykle układają się tak:",
    "rows": [
        {
            "en": "Manner",
            "ua": "jak?",
            "note": "hard, quickly, well"
        },
        {
            "en": "Place",
            "ua": "gdzie?",
            "note": "in London, at home, here"
        },
        {
            "en": "Time",
            "ua": "kiedy?",
            "note": "yesterday, last year, every day"
        }
    ],
    "warning": "📌 Przykład: <strong>She worked hard in London last year.</strong>"
}

{
    "title": "7. Przysłówki stopnia",
    "sections": [
        {
            "label": "Przed wyrazem, który opisują",
            "color": "emerald",
            "description": "Przysłówki <strong>very, quite, really, extremely, fairly</strong> stoją zwykle przed słowem, które modyfikują.",
            "examples": [
                {
                    "en": "She is very smart.",
                    "ua": "Ona jest bardzo bystra."
                },
                {
                    "en": "He runs quite fast.",
                    "ua": "On biega całkiem szybko."
                },
                {
                    "en": "The movie was extremely boring.",
                    "ua": "Film był strasznie nudny."
                }
            ]
        },
        {
            "label": "A lot / very much",
            "color": "sky",
            "description": "Wyrażenia typu <strong>a lot</strong> albo <strong>very much</strong> często stoją pod koniec zdania.",
            "examples": [
                {
                    "en": "We travel a lot.",
                    "ua": "Dużo podróżujemy."
                },
                {
                    "en": "I like it very much.",
                    "ua": "Bardzo mi się to podoba."
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Przysłówek sposobu w złym miejscu.",
            "wrong": "She speaks fluently English.",
            "right": "✅ <span class=\"font-mono\">She speaks English fluently.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przysłówek częstotliwości na początku zamiast przed czasownikiem.",
            "wrong": "Always I drink coffee.",
            "right": "✅ <span class=\"font-mono\">I always drink coffee.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła pozycja przysłówka częstotliwości.",
            "wrong": "He goes often to the gym.",
            "right": "✅ <span class=\"font-mono\">He often goes to the gym.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Okolicznik czasu w nienaturalnym miejscu.",
            "wrong": "I yesterday saw him.",
            "right": "✅ <span class=\"font-mono\">I saw him yesterday.</span>"
        }
    ]
}

{
    "title": "10. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny wariant",
    "select_intro": "Wskaż zdanie z naturalnym miejscem przysłówka.",
    "selects": [
        {
            "label": "a) She always drinks coffee. / b) She drinks always coffee.",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) He speaks fluently English. / b) He speaks English fluently.",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) I yesterday saw him. / b) I saw him yesterday.",
            "prompt": "Który wariant jest poprawny?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Wstaw przysłówek we właściwe miejsce",
    "input_intro": "Umieść brakujący element w naturalnej pozycji.",
    "inputs": [
        {
            "before": "She is late. (always)",
            "after": "→"
        },
        {
            "before": "He plays the piano. (well)",
            "after": "→"
        },
        {
            "before": "They work. / in the office / every day",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw niepoprawne ustawienie przysłówka.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Always he is happy.",
            "example_target": "He is always happy."
        },
        {
            "original": "1. She speaks well French.",
            "placeholder": "Popraw szyk"
        },
        {
            "original": "2. Never I have been to Japan.",
            "placeholder": "Popraw szyk"
        }
    ]
}

{
    "title": "Strony w sekcji Word Order",
    "items": [
        {
            "label": "Basic Word Order",
            "current": false
        },
        {
            "label": "Pytania i przeczenia",
            "current": false
        },
        {
            "label": "Przysłówki w zdaniu",
            "current": true
        },
        {
            "label": "Word Order with Verbs and Objects",
            "current": false
        },
        {
            "label": "Advanced Word Order / Emphasis",
            "current": false
        }
    ]
}
